import React from 'react';
import { ThemeProvider, useTheme } from './ThemeContext';
import './styles.css';

function ThemeDemo() {
  const { theme, toggleTheme, setTheme } = useTheme();

  return (
    <div className={`themed themed--${theme}`} data-testid="themed-container" data-theme={theme}>
      <h1>Theme Context</h1>
      <p>Current theme: <strong data-testid="theme-display">{theme}</strong></p>
      <div className="themed__actions">
        <button data-testid="toggle-theme" onClick={toggleTheme}>Toggle Theme</button>
        <button data-testid="set-light" onClick={() => setTheme('light')}>Light</button>
        <button data-testid="set-dark" onClick={() => setTheme('dark')}>Dark</button>
      </div>
    </div>
  );
}

export default function App() {
  return (
    <ThemeProvider>
      <ThemeDemo />
    </ThemeProvider>
  );
}

