import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { ThemeProvider, useTheme } from './ThemeContext';

function TestConsumer() {
  const { theme, toggleTheme, setTheme } = useTheme();
  return (
    <div>
      <span data-testid="theme-display">{theme}</span>
      <button data-testid="toggle-theme" onClick={toggleTheme}>Toggle</button>
      <button data-testid="set-light" onClick={() => setTheme('light')}>Light</button>
      <button data-testid="set-dark" onClick={() => setTheme('dark')}>Dark</button>
    </div>
  );
}

describe('ThemeContext', () => {
  it('provides light theme by default', () => {
    render(<ThemeProvider><TestConsumer /></ThemeProvider>);
    expect(screen.getByTestId('theme-display')).toHaveTextContent('light');
  });

  it('toggles to dark theme', () => {
    render(<ThemeProvider><TestConsumer /></ThemeProvider>);
    fireEvent.click(screen.getByTestId('toggle-theme'));
    expect(screen.getByTestId('theme-display')).toHaveTextContent('dark');
  });

  it('toggles back to light', () => {
    render(<ThemeProvider><TestConsumer /></ThemeProvider>);
    fireEvent.click(screen.getByTestId('toggle-theme'));
    fireEvent.click(screen.getByTestId('toggle-theme'));
    expect(screen.getByTestId('theme-display')).toHaveTextContent('light');
  });

  it('setTheme sets dark directly', () => {
    render(<ThemeProvider><TestConsumer /></ThemeProvider>);
    fireEvent.click(screen.getByTestId('set-dark'));
    expect(screen.getByTestId('theme-display')).toHaveTextContent('dark');
  });

  it('setTheme sets light directly', () => {
    render(<ThemeProvider><TestConsumer /></ThemeProvider>);
    fireEvent.click(screen.getByTestId('set-dark'));
    fireEvent.click(screen.getByTestId('set-light'));
    expect(screen.getByTestId('theme-display')).toHaveTextContent('light');
  });

  it('useTheme throws outside provider', () => {
    const spy = jest.spyOn(console, 'error').mockImplementation(() => {});
    expect(() => render(<TestConsumer />)).toThrow();
    spy.mockRestore();
  });
});

